import json
with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

def extract(data):
    result = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            for pkg in fw.get('topLevelPackages', []):
                result[(name, pkg['id'])] = pkg['resolvedVersion']
    return result

b = extract(baseline)
a = extract(after)
changes = []
for key in sorted(set(b.keys()) | set(a.keys())):
    bv = b.get(key)
    av = a.get(key)
    if bv != av:
        changes.append(f'{key[0]} | {key[1]} | {bv} -> {av}')
if changes:
    print('CHANGES DETECTED:')
    for c in changes: print(c)
else:
    print('No version changes - conversion is fully version-neutral.')
"

